sql:
SELECT animal_name, average_weight
FROM animals
WHERE average_weight > 50;

external_knowledge:
- 'Long-lived creatures': refers to animals with an average lifespan > 15 years;
- 'Top three longest-lived positions': ranking within each category based on lifespan, descending;
- 'Typical brief existence': typically less than 15 years lifespan.

sql:
SELECT conservation_status, description
FROM conservation_statuses
WHERE urgency_level <= 3;

SELECT category_name
FROM categories
WHERE category_id < 5;

SELECT COUNT(animal_id) AS number_of_animals
FROM animals
WHERE category_id = 1 AND conservation_status_id = 1;
